    &#125;)

    &#x2F;&#x2F; 根据 &#96;[]map[string]interface&#123;&#125;&#123;&#125;&#96; 批量插入
    db.Model(&amp;User&#123;&#125;).Create([]map[string]interface&#123;&#125;&#123;
        &#123;&quot;Name&quot;: &quot;&quot;, &quot;Age&quot;: nil&#125;,
        &#123;&quot;Name&quot;: &quot;&quot;, &quot;Age&quot;: nil&#125;,
        &#123;&#125;,
    &#125;)
