创建时的Hook操作// 开始事务BeforeSaveBeforeCreate// 关联前的 save// 插入记录至 db // 关联后的 saveAfterCreate AfterSave// 提交或回滚事务
更新数据
  使用Save方法 会保存所有的字段，即使字段是零值


&#x2F;&#x2F;修改
func update() &#123;
	&#x2F;&#x2F;更新单列
	var user User
	user.Name &#x3D; &quot;迁客骚人&quot;
	user.Age &#x3D; 100
	db.Save(&amp;user)
	fmt.Println(user.Name)

	&#x2F;&#x2F; 条件更新
	db.Model(&amp;User&#123;&#125;).Where(&quot;active &#x3D; ?&quot;, true).Update(&quot;name&quot;, &quot;hello&quot;)
	&#x2F;&#x2F; UPDATE users SET name&#x3D;&#39;hello&#39;, updated_at&#x3D;&#39;2013-11-17 21:34:10&#39; WHERE active&#x3D;true;

	&#x2F;&#x2F; User 的 ID 是 &#96;111&#96;
	db.Model(&amp;user).Update(&quot;name&quot;, &quot;hello&quot;)
	&#x2F;&#x2F; UPDATE users SET name&#x3D;&#39;hello&#39;, updated_at&#x3D;&#39;2013-11-17 21:34:10&#39; WHERE id&#x3D;111;

	&#x2F;&#x2F; 根据条件和 model 的值进行更新
	db.Model(&amp;user).Where(&quot;active &#x3D; ?&quot;, true).Update(&quot;name&quot;, &quot;hello&quot;)
	&#x2F;&#x2F; UPDATE users SET name&#x3D;&#39;hello&#39;, updated_at&#x3D;&#39;2013-11-17 21:34:10&#39; WHERE id&#x3D;111 AND active&#x3D;true;

	&#x2F;&#x2F; 根据 &#96;struct&#96; 更新属性，只会更新非零值的字段
	db.Model(&amp;user).Updates(User&#123;Name: &quot;hello&quot;, Age: 18&#125;)
	&#x2F;&#x2F; UPDATE users SET name&#x3D;&#39;hello&#39;, age&#x3D;18, updated_at &#x3D; &#39;2013-11-17 21:34:10&#39; WHERE id &#x3D; 111;

	&#x2F;&#x2F; 根据 &#96;map&#96; 更新属性
	db.Model(&amp;user).Updates(map[string]interface&#123;&#125;&#123;&quot;Name&quot;: &quot;hello&quot;, &quot;Age&quot;: 18&#125;)
	&#x2F;&#x2F; UPDATE users SET name&#x3D;&#39;hello&#39;, age&#x3D;18, actived&#x3D;false, updated_at&#x3D;&#39;2013-11-17 21:34:10&#39; WHERE id&#x3D;111;

	&#x2F;&#x2F;批量更新
	&#x2F;&#x2F; 根据 struct 更新
	db.Model(User&#123;&#125;).Where(&quot;role &#x3D; ?&quot;, &quot;admin&quot;).Updates(User&#123;Name: &quot;wmq&quot;, Age: 18&#125;)
	&#x2F;&#x2F; UPDATE users SET name&#x3D;&#39;hello&#39;, age&#x3D;18 WHERE role &#x3D; &#39;admin;

	&#x2F;&#x2F; 根据 map 更新
	db.Table(&quot;users&quot;).Where(&quot;id IN ?&quot;, []int&#123;10, 11&#125;).Updates(map[string]interface&#123;&#125;&#123;&quot;name&quot;: &quot;hello&quot;, &quot;age&quot;: 18&#125;)
	&#x2F;&#x2F; UPDATE users SET name&#x3D;&#39;hello&#39;, age&#x3D;18 WHERE id IN (10, 11);
&#125;


xorm的CRUD操作xorm的特性
支持Struct和数据库表之间的灵活映射，并支持自动同步
事务支持
同时支持原始SQL语句和ORM操作的混合执行
使用连写来简化调用
支持使用Id, In, Where, Limit, Join, Having, Table, SQL, Cols等函数和结构体等方式作为条件
支持级联加载Struct
Schema支持（仅Postgres）
支持缓存
支持根据数据库自动生成xorm的结构体
支持记录版本（即乐观锁）
内置SQL Builder支持
通过EngineGroup支持读写分离和负载均衡

